"use client";

import { motion, Variants } from "framer-motion";
import { Sparkles, User } from "lucide-react";
import React from "react";

interface MotionMessageProps {
  role: "user" | "assistant";
  content: string;
  isStreaming?: boolean;
}

// Animation variants
const messageVariants: Variants = {
  hidden: {
    opacity: 0,
    y: 20,
    scale: 0.95,
  },
  visible: {
    opacity: 1,
    y: 0,
    scale: 1,
    transition: {
      type: "spring" as const,
      stiffness: 260,
      damping: 20,
      duration: 0.3,
    },
  },
  exit: {
    opacity: 0,
    y: -10,
    transition: {
      duration: 0.2,
    },
  },
};

// Function to format message with code blocks and inline code
function formatMessage(text: string): React.ReactNode {
  if (!text) return null;

  // Normalize newlines
  const normalized = text
    .replace(/\\n/g, "\n")
    .replace(/\\r/g, "")
    .replace(/\\t/g, "  ");

  // Split by code blocks
  const parts = normalized.split(/(```[\s\S]*?```)/g);

  return parts.map((part, index) => {
    // Code block
    if (part.startsWith("```")) {
      const match = part.match(/```(\w+)?\n([\s\S]*?)```/);
      if (match) {
        const [, lang = "", code] = match;
        return (
          <div
            key={index}
            className="my-4 rounded-lg overflow-hidden border border-[#3c4043]"
          >
            <div className="flex items-center justify-between px-4 py-2 bg-[#2d2d2e] border-b border-[#3c4043]">
              <span className="text-xs text-gemini-text-muted">
                {lang || "code"}
              </span>
              <button
                onClick={() => navigator.clipboard.writeText(code.trim())}
                className="text-xs text-gemini-text-muted hover:text-gemini-text-primary transition-colors"
              >
                Copy
              </button>
            </div>
            <pre className="p-4 overflow-x-auto bg-[#1e1f20]">
              <code className="text-sm font-mono text-gemini-text-primary whitespace-pre">
                {code.trim()}
              </code>
            </pre>
          </div>
        );
      }
    }

    // Regular text with inline code
    const textParts = part.split(/(`[^`]+`)/g);
    return (
      <span key={index}>
        {textParts.map((textPart, textIndex) => {
          if (textPart.startsWith("`") && textPart.endsWith("`")) {
            return (
              <code
                key={textIndex}
                className="px-1.5 py-0.5 bg-[#2d2d2e] rounded text-sm font-mono text-teal-400"
              >
                {textPart.slice(1, -1)}
              </code>
            );
          }
          // Handle line breaks
          return (
            <span key={textIndex}>
              {textPart.split("\n").map((line, lineIndex, arr) => (
                <React.Fragment key={lineIndex}>
                  {line}
                  {lineIndex < arr.length - 1 && <br />}
                </React.Fragment>
              ))}
            </span>
          );
        })}
      </span>
    );
  });
}

export default function MotionMessage({
  role,
  content,
  isStreaming,
}: MotionMessageProps) {
  const isAI = role === "assistant";

  return (
    <motion.div
      variants={messageVariants}
      initial="hidden"
      animate="visible"
      exit="exit"
      className="flex gap-4 group py-4"
    >
      {/* Avatar */}
      <div
        className={`w-8 h-8 rounded-full flex shrink-0 items-center justify-center shadow-lg ${
          isAI
            ? "bg-[#1e1f20] border border-[#3c4043]"
            : "bg-gradient-to-br from-teal-500 to-blue-600"
        }`}
      >
        {isAI ? (
          <Sparkles size={16} className="text-teal-400" />
        ) : (
          <User size={16} className="text-white" />
        )}
      </div>

      {/* Message Content */}
      <div className="flex-1 space-y-1 pt-1 min-w-0">
        <div
          className={`leading-relaxed text-[15px] text-gemini-text-primary ${
            isStreaming ? "prose-stream" : ""
          }`}
        >
          {formatMessage(content)}
        </div>
      </div>
    </motion.div>
  );
}
