"use client";

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, Sparkles } from "lucide-react";
import Sidebar from "../components/Sidebar";
import ChatInput from "../components/ChatInput";
import MotionMessage from "../components/MotionMessage";

interface Message {
  id: string;
  role: "user" | "assistant";
  content: string;
}

interface Chat {
  id: string;
  title: string;
  messages: Message[];
  timestamp: Date;
}

export default function GeminiChatPage() {
  const [chats, setChats] = useState<Chat[]>([]);
  const [currentChatId, setCurrentChatId] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [activeEngine, setActiveEngine] = useState<"groq" | "hf">("groq");
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chats, currentChatId]);

  // Get current chat
  const currentChat = chats.find((c) => c.id === currentChatId);

  // Create new chat
  const handleNewChat = () => {
    const newChat: Chat = {
      id: Date.now().toString(),
      title: "New conversation",
      messages: [],
      timestamp: new Date(),
    };
    setChats((prev) => [newChat, ...prev]);
    setCurrentChatId(newChat.id);
  };

  // Select chat
  const handleSelectChat = (id: string) => {
    setCurrentChatId(id);
  };

  // Send message
  const handleSendMessage = async (content: string) => {
    if (!content.trim()) return;

    // Create chat if none exists
    let chatId = currentChatId;
    if (!chatId) {
      const newChat: Chat = {
        id: Date.now().toString(),
        title: content.slice(0, 30) + (content.length > 30 ? "..." : ""),
        messages: [],
        timestamp: new Date(),
      };
      setChats((prev) => [newChat, ...prev]);
      chatId = newChat.id;
      setCurrentChatId(chatId);
    }

    // Add user message
    const userMessage: Message = {
      id: Date.now().toString(),
      role: "user",
      content,
    };

    setChats((prev) =>
      prev.map((chat) =>
        chat.id === chatId
          ? { ...chat, messages: [...chat.messages, userMessage] }
          : chat
      )
    );

    // Simulate AI response
    setIsLoading(true);
    setTimeout(() => {
      const aiMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: "assistant",
        content: `I'm Nyati-core01. You said: "${content}"\n\nThis is a simulated response. In the real implementation, this would call the Groq/HF API with streaming support.`,
      };

      setChats((prev) =>
        prev.map((chat) =>
          chat.id === chatId
            ? { ...chat, messages: [...chat.messages, aiMessage] }
            : chat
        )
      );
      setIsLoading(false);
    }, 1500);
  };

  // Switch engine
  const handleSwitchEngine = () => {
    setActiveEngine((prev) => (prev === "groq" ? "hf" : "groq"));
  };

  return (
    <div className="flex h-screen bg-[#0e0e0e] text-foreground overflow-hidden">
      {/* Sidebar */}
      <Sidebar
        isOpen={sidebarOpen}
        setIsOpen={setSidebarOpen}
        onNewChat={handleNewChat}
        chats={chats}
        currentChatId={currentChatId}
        onSelectChat={handleSelectChat}
        activeEngine={activeEngine}
        onSwitchEngine={handleSwitchEngine}
      />

      {/* Main Content - Added min-w-0 to prevent overflow */}
      <main
        className={`flex-1 flex flex-col min-w-0 relative transition-all duration-300 ${
          sidebarOpen ? "md:ml-[280px]" : ""
        }`}
      >
        {/* Mobile Header */}
        <header className="flex items-center justify-between p-4 md:px-6 z-10 bg-[#0e0e0e]/80 backdrop-blur-md md:hidden border-b border-border/50">
          <div className="flex items-center gap-4">
            <button
              onClick={() => setSidebarOpen(!sidebarOpen)}
              className="p-2 hover:bg-secondary rounded-full transition-colors"
            >
              <Menu size={22} />
            </button>
            <span className="font-semibold text-lg bg-gradient-to-r from-teal-400 to-blue-500 bg-clip-text text-transparent">
              Koda-A
            </span>
          </div>
          <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-teal-500 to-blue-600 flex items-center justify-center text-xs font-bold text-white">
            K
          </div>
        </header>

        {/* Chat Messages - Centered content */}
        <div className="flex-1 overflow-y-auto px-4 md:px-8 scrollbar-hide">
          <div className="max-w-3xl mx-auto py-8 min-h-full">
            {currentChat && currentChat.messages.length > 0 ? (
              <div className="space-y-2 pb-32">
                <AnimatePresence mode="popLayout">
                  {currentChat.messages.map((message) => (
                    <MotionMessage
                      key={message.id}
                      role={message.role}
                      content={message.content}
                    />
                  ))}
                </AnimatePresence>
                {isLoading && (
                  <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="flex gap-4 py-4"
                  >
                    <div className="w-8 h-8 rounded-full bg-secondary border border-border flex items-center justify-center shrink-0">
                      <Sparkles size={16} className="text-teal-400" />
                    </div>
                    <div className="flex-1 pt-1">
                      <div className="thinking-shimmer" />
                      <div className="thinking-shimmer w-40" />
                    </div>
                  </motion.div>
                )}
                <div ref={messagesEndRef} className="h-4" />
              </div>
            ) : (
              /* Welcome Screen - Properly centered */
              <div className="flex flex-col items-center justify-center min-h-[70vh]">
                <motion.div
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="flex flex-col items-center text-center"
                >
                  <div className="w-20 h-20 rounded-full bg-gradient-to-tr from-teal-500 to-blue-600 flex items-center justify-center mb-6 shadow-lg shadow-teal-500/20">
                    <Sparkles size={40} className="text-white" />
                  </div>
                  <h1 className="text-4xl md:text-5xl font-bold bg-gradient-to-r from-teal-400 via-blue-400 to-purple-400 bg-clip-text text-transparent mb-4">
                    Hello there
                  </h1>
                  <p className="text-xl text-muted-foreground mb-8">
                    How can I help you today?
                  </p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full max-w-2xl">
                    {[
                      "Help me write code",
                      "Summarize a document",
                      "Brainstorm ideas",
                      "Explain a concept",
                    ].map((suggestion, index) => (
                      <motion.button
                        key={index}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: index * 0.1 }}
                        onClick={() => handleSendMessage(suggestion)}
                        className="p-4 text-left bg-card hover:bg-secondary border border-border hover:border-muted-foreground/50 rounded-2xl transition-all group"
                      >
                        <p className="text-muted-foreground group-hover:text-foreground transition-colors">
                          {suggestion}
                        </p>
                      </motion.button>
                    ))}
                  </div>
                </motion.div>
              </div>
            )}
          </div>
        </div>

        {/* Chat Input - Floating at bottom */}
        <ChatInput onSend={handleSendMessage} isLoading={isLoading} />
      </main>
    </div>
  );
}
